    (function () {
    let cheqEvtReceived = false;

    document.body.addEventListener("cheqEvt", function (event) {
        cheqEvtReceived = true;
        const data = event.detail;
        if (data && typeof data === "object") {
            const cheqTT = (data.cheqObj && data.cheqObj.cheqTT) || '';
            if (!CHEQ_BLOCKED_REASONS.includes(cheqTT)) {
                doRedirect();
            }
            return;
        }
        doRedirect();
    });

    setTimeout(function () {
        if (!cheqEvtReceived) {
            doRedirect();
        }
    }, 500);
})();
